/// 将 URI path 转为项目/文件键（使用文件系统路径，统一为 / 分隔符）
fn uri_to_key(uri: &Url) -> String {
    // 优先使用文件系统路径，回退到 URI.path(); 统一为 `/` 分隔，去掉前导 `/`，Windows 驱动器字母小写化
    let raw = uri
        .to_file_path()
        .ok()
        .and_then(|p| p.to_str().map(|s| s.replace('\\', "/")))
        .unwrap_or_else(|| uri.path().to_string());
    let s = raw.trim_start_matches('/').to_string();
    // Windows 驱动器小写化: C:/... -> c:/...
    if s.len() >= 2 && s.as_bytes().get(1) == Some(&b':') {
        let mut chars: Vec<char> = s.chars().collect();
        chars[0] = chars[0].to_ascii_lowercase();
        return chars.into_iter().collect();
    }
    s
}

/// 获取配置文件的 parent key（项目键）
fn parent_key_from_uri(uri: &Url) -> String {
    // 获取父目录路径并进行与 uri_to_key 相同的规范化
    if let Some(parent_path) = uri.to_file_path().ok().and_then(|p| {
        p.parent()
            .and_then(|pp| pp.to_str().map(|s| s.replace('\\', "/")))
    }) {
        let s = parent_path.trim_start_matches('/').to_string();
        if s.len() >= 2 && s.as_bytes().get(1) == Some(&b':') {
            let mut chars: Vec<char> = s.chars().collect();
            chars[0] = chars[0].to_ascii_lowercase();
            return chars.into_iter().collect();
        }
        return s;
    }
    let path = uri.path();
    let p = path.rfind('/').map(|i| &path[..i]).unwrap_or(path);
    let p = p.trim_start_matches('/').to_string();
    if p.len() >= 2 && p.as_bytes().get(1) == Some(&b':') {
        let mut chars: Vec<char> = p.chars().collect();
        chars[0] = chars[0].to_ascii_lowercase();
        return chars.into_iter().collect();
    }
    path_tree::canonicalize(&p).unwrap_or(p)
}

/// 后端状态：Client + workspace projects
#[derive(Debug)]
pub struct Backend {
    client: Client,
    workspace: RwLock<Folder<Arc<RwLock<Context>>>>,
    workspace_folders: RwLock<Option<Vec<WorkspaceFolder>>>,
}

impl Backend {
    pub fn new(client: Client) -> Self {
        Self {
            client,
            workspace: RwLock::new(Folder::new()),
            workspace_folders: RwLock::new(None),
        }
    }

    /// General update entry: dispatch to scene or resource handlers
    async fn update(&self, uri: Url, content: String) {
        if uri.path().contains("/scene/") && uri.path().ends_with(".txt") {
            self.process_scene_update(uri, content).await;
        } else {
            self.process_resource_update(uri, content).await;
        }
    }

    async fn process_scene_update(&self, uri: Url, content: String) {
        if let Some(ctx_arc) = self.find_context_for_doc(&uri).await {
            // 统一使用 find_scene_key_for_uri 来计算相对于 scene/ 的键
            match self.find_scene_key_for_uri(&uri).await {
                Some(scene_key) => {
                    tracing::debug!(%scene_key, %uri, "Updating scene");
                    let mut ctx = ctx_arc.write().await;
                    if let Err(e) = ctx.update_scene(&scene_key, Scene::from_str(content)) {
                        tracing::error!(%scene_key, "Failed to update scene: {}", e);
                    }
                    drop(ctx);
                    self.publish_all_diagnostics(&ctx_arc).await;
                }
                None => tracing::warn!(%uri, "Failed to compute scene key for update"),
            }
        } else {
            tracing::warn!("No project context found for scene {}", uri);
        }
    }

    async fn process_resource_update(&self, uri: Url, content: String) {
        if let Some(ctx_arc) = self.find_context_for_doc(&uri).await {
            // find the project key in workspace that corresponds to this ctx
            let project_key = {
                let workspace = self.workspace.read().await;
                let mut found: Option<String> = None;
                for (k, n) in workspace.iter_recursively() {
                    if let Some(item) = n.as_item()
                        && Arc::ptr_eq(item, &ctx_arc)
                    {
                        found = Some(k.to_string());
                        break;
                    }
                }
                found
            };

            let key = match project_key {
                Some(k) => k,
                None => return,
            };

            let doc_key = uri_to_key(&uri);

            let rel = if doc_key.len() > key.len()
                && doc_key.starts_with(&key)
                && doc_key.as_bytes().get(key.len()) == Some(&b'/')
            {
                &doc_key[key.len() + 1..]
            } else if doc_key == key {
                ""
            } else {
                &doc_key[..]
            };

            let mut ctx = ctx_arc.write().await;
            // 插入时去掉顶层目录前缀，Folder 中存储的是相对于各资源目录的路径
            if let Some(stripped) = rel.strip_prefix("animation/") {
                if stripped.ends_with(".json") {
                    ctx.resource.animation.insert(stripped, Node::Item(()));
                }
            } else if let Some(stripped) = rel.strip_prefix("background/") {
                ctx.resource.background.insert(stripped, Node::Item(()));
            } else if let Some(stripped) = rel.strip_prefix("figure/") {
                if let Err(e) = ctx.resource.insert_figure(stripped, &content) {
                    tracing::error!(%stripped, "Failed to insert figure: {}", e);
                }
            } else if let Some(stripped) = rel.strip_prefix("bgm/") {
                ctx.resource.bgm.insert(stripped, Node::Item(()));
            } else if let Some(stripped) = rel.strip_prefix("vocal/") {
                ctx.resource.vocal.insert(stripped, Node::Item(()));
            } else if let Some(stripped) = rel.strip_prefix("video/") {
                ctx.resource.video.insert(stripped, Node::Item(()));
            }
            drop(ctx);
            // 资源更新后重新发布所有诊断以反映资源对场景的影响
            self.publish_all_diagnostics(&ctx_arc).await;
        }
    }

    /// 扫描项目资源目录并将结果写入 Context（在后台收集文件列表，避免在持有锁时做阻塞 IO）
    async fn scan_project_resources(&self, key: &str, ctx_arc: &Arc<RwLock<Context>>) {
        let key_path = std::path::PathBuf::from(key.to_string());
        // 在阻塞线程中遍历文件系统并收集资源条目
        #[derive(Debug)]
        enum EntryKind {
            Animation(String),
            Background(String),
            Figure(String, Option<String>),
            Bgm(String),
            Vocal(String),
            Video(String),
        }

        let entries = tokio::task::spawn_blocking(move || {
            fn walk(
                base: &std::path::Path,
                cur: &std::path::Path,
                kind: &str,
                out: &mut Vec<EntryKind>,
            ) {
                if let Ok(rd) = std::fs::read_dir(cur) {
                    for e in rd.flatten() {
                        let p = e.path();
                        if p.is_dir() {
                            walk(base, &p, kind, out);
                        } else {
                            // 相对于资源目录的路径，不包含顶层 kind 前缀
                            if let Ok(rel) = p.strip_prefix(base) {
                                let rel = rel.to_string_lossy().replace('\\', "/");
                                match kind {
                                    "animation" => out.push(EntryKind::Animation(rel)),
                                    "background" => out.push(EntryKind::Background(rel)),
                                    "figure" => {
                                        let content = std::fs::read_to_string(&p).ok();
                                        out.push(EntryKind::Figure(rel, content));
                                    }
                                    "bgm" => out.push(EntryKind::Bgm(rel)),
                                    "vocal" => out.push(EntryKind::Vocal(rel)),
                                    "video" => out.push(EntryKind::Video(rel)),
                                    _ => {}
                                }
                            }
                        }
                    }
                }
            }

            let mut out = Vec::new();
            for sub in ["animation", "background", "figure", "bgm", "vocal", "video"] {
                let dir = key_path.join(sub);
                if dir.exists() && dir.is_dir() {
                    walk(&dir, &dir, sub, &mut out);
                }
            }
            out
        })
        .await
        .unwrap_or_default();

        if entries.is_empty() {
            return;
        }

        let mut ctx = ctx_arc.write().await;
        for entry in entries {
            match entry {
                EntryKind::Animation(rel) => {
                    ctx.resource.animation.insert(&rel, Node::Item(()));
                }
                EntryKind::Background(rel) => {
                    ctx.resource.background.insert(&rel, Node::Item(()));
                }
                EntryKind::Figure(rel, content) => {
                    if let Some(content) = content {
                        let _ = ctx.resource.insert_figure(&rel, &content);
                    } else {
                        // 未能读取内容时仅插入空占位
                        ctx.resource
                            .figure
                            .insert(&rel, Node::Item(webgal_model::resource::FigureInfo::new()));
                    }
                }
                EntryKind::Bgm(rel) => {
                    ctx.resource.bgm.insert(&rel, Node::Item(()));
                }
                EntryKind::Vocal(rel) => {
                    ctx.resource.vocal.insert(&rel, Node::Item(()));
                }
                EntryKind::Video(rel) => {
                    ctx.resource.video.insert(&rel, Node::Item(()));
                }
            }
        }
    }

    /// 为项目中的所有场景（`resource.scene`）计算并发布诊断（先收集再发送，避免持锁调用 publish）
    async fn publish_all_diagnostics(&self, ctx_arc: &Arc<RwLock<Context>>) {
        // 先查找该 ctx 对应的项目 key（相对于 workspace）
        let project_key = {
            let workspace = self.workspace.read().await;
            let mut found: Option<String> = None;
            for (k, n) in workspace.iter_recursively() {
                if let Some(item) = n.as_item()
                    && Arc::ptr_eq(item, ctx_arc)
                {
                    found = Some(k.to_string());
                    break;
                }
            }
            found
        };

        // 在读锁下收集所有 (scene_rel_path, diagnostics)
        let diagnostics_list: Vec<(String, Vec<Diagnostic>)> = {
            let ctx = ctx_arc.read().await;
            let mut out = Vec::new();
            for (path, node) in ctx.resource.scene.iter_recursively() {
                if let Some(scene) = node.as_item() {
                    let diags = diagnose_scene(scene, &ctx);
                    out.push((path.clone(), diags));
                }
            }
            out
        };

        // 释放锁后再次构造完整 URI 并发送诊断
        for (rel_path, diags) in diagnostics_list {
            // 尝试基于 scene 将 diagnostics 从 UTF-8 转为 UTF-16
            let mut converted: Vec<Diagnostic> = Vec::new();
            {
                let ctx = ctx_arc.read().await;
                if let Some(scene) = ctx.resource.scene.get(&rel_path).and_then(Node::as_item) {
                    for d in diags.into_iter() {
                        if let Some(range) = range_utf8_to_utf16(scene, d.range) {
                            converted.push(Diagnostic { range, ..d });
                        } else {
                            // fallback: push original diagnostic if conversion failed
                            converted.push(d);
                        }
                    }
                } else {
                    converted = diags;
                }
            }

            if let Some(key) = &project_key {
                let full = std::path::PathBuf::from(key).join("scene").join(&rel_path);
                let uri = Url::from_file_path(&full).unwrap_or_else(|_| {
                    Url::parse(&format!("file:///{}", full.display())).unwrap()
                });
                let _ = self.client.publish_diagnostics(uri, converted, None).await;
            } else {
                // fallback: try treat rel_path as absolute or file path
                let full = std::path::PathBuf::from(&rel_path);
                let uri = Url::from_file_path(&full)
                    .unwrap_or_else(|_| Url::parse(&format!("file:///{}", rel_path)).unwrap());
                let _ = self.client.publish_diagnostics(uri, converted, None).await;
            }
        }
    }

    /// 在给定根路径下递归查找所有名为 `config.txt` 的文件并返回它们的 Url 列表
    async fn find_config_files(&self, root: &std::path::Path) -> Vec<Url> {
        let mut configs = Vec::new();
        if !root.exists() {
            return configs;
        }

        let mut stack = vec![root.to_path_buf()];
        while let Some(dir) = stack.pop() {
            let rd = tokio::fs::read_dir(&dir).await;
            let mut rd = match rd {
                Ok(r) => r,
                Err(_) => continue,
            };
            while let Ok(Some(entry)) = rd.next_entry().await {
                let path = entry.path();
                if path.is_dir() {
                    stack.push(path);
                } else if path.file_name().and_then(|n| n.to_str()) == Some("config.txt")
                    && let Ok(url) = Url::from_file_path(&path)
                {
                    configs.push(url);
                }
            }
        }
        configs
    }

    /// 递归扫描项目的 scene 目录，解析所有 .txt 场景并写入 Context
    async fn scan_all_scenes(&self, key: &str, ctx_arc: &Arc<RwLock<Context>>) {
        let scenes_dir = std::path::Path::new(key).join("scene");
        if !scenes_dir.exists() {
            return;
        }

        let mut stack = vec![scenes_dir.clone()];
        while let Some(dir) = stack.pop() {
            let rd = tokio::fs::read_dir(&dir).await;
            let mut rd = match rd {
                Ok(r) => r,
                Err(_) => continue,
            };
            while let Ok(Some(entry)) = rd.next_entry().await {
                let path = entry.path();
                if path.is_dir() {
                    stack.push(path);
                } else if path.extension().and_then(|e| e.to_str()) == Some("txt")
                    && let Ok(content) = tokio::fs::read_to_string(&path).await
                {
                    // 生成相对于 scene/ 目录的相对路径作为场景键
                    if let Ok(rel) = path.strip_prefix(&scenes_dir) {
                        let rel_path = rel.to_string_lossy().replace('\\', "/");
                        let scene = Scene::from_str(&content);
                        let mut ctx = ctx_arc.write().await;
                        if let Err(e) = ctx.update_scene(&rel_path, scene) {
                            tracing::error!(%rel_path, "Failed to preload scene: {}", e);
                        }
                    }
                }
            }
        }
    }

    /// 基于 workspace folders 自动发现项目：查找 config.txt、创建 Context、扫描资源与场景并发布诊断
    async fn discover_projects(&self) {
        let folders_opt = { self.workspace_folders.read().await.clone() };
        let folders = match folders_opt {
            Some(f) => f,
            None => return,
        };

        for folder in folders {
            // 尝试将 WorkspaceFolder.uri 转为文件系统路径
            let root_path = match folder.uri.to_file_path() {
                Ok(p) => p,
                Err(_) => continue,
            };

            let configs = self.find_config_files(&root_path).await;
            tracing::debug!(root = %root_path.display(), configs = configs.len(), "Found config files in workspace folder");
            for config_uri in configs {
                tracing::debug!(config = %config_uri.as_str(), "Found config file");
                let key = parent_key_from_uri(&config_uri);
                // 已存在则跳过
                if self.workspace.read().await.get(&key).is_some() {
                    continue;
                }

                // 新建 Context 并插入 workspace
                let ctx = Context::new();
                let arc = Arc::new(RwLock::new(ctx));
                {
                    let mut ws = self.workspace.write().await;
                    ws.insert(&key, Node::Item(arc.clone()));
                }

                // 填充资源并预加载场景
                self.scan_project_resources(&key, &arc).await;
                self.scan_all_scenes(&key, &arc).await;
                self.publish_all_diagnostics(&arc).await;
                tracing::info!(%key, "Auto-discovered WebGAL project");
            }
        }
    }

    /// 查找对应的项目 Context（基于 URI.path 的 prefix longest match）
    async fn find_context_for_doc(&self, uri: &Url) -> Option<Arc<RwLock<Context>>> {
        let doc_key = uri_to_key(uri);
        tracing::debug!(%doc_key, "Looking for context for document");
        let workspace = self.workspace.read().await;
        let mut best: Option<(usize, Arc<RwLock<Context>>)> = None;
        for (key, node) in workspace.iter_recursively() {
            if doc_key.starts_with(&key)
                && (doc_key.len() == key.len() || doc_key.as_bytes().get(key.len()) == Some(&b'/'))
                && let Some(item) = node.as_item()
            {
                let len = key.len();
                let arc = item.clone();
                if best.as_ref().is_none_or(|(bestlen, _)| len > *bestlen) {
                    best = Some((len, arc));
                }
            }
        }
        let result = best.map(|(_, arc)| arc);
        if result.is_some() {
            tracing::debug!(%doc_key, "Found matching context");
        } else {
            tracing::debug!(%doc_key, "No matching context found");
        }
        result
    }

    /// 查找项目键（与 find_context_for_doc 类似，但返回字符串 key）
    async fn find_project_key_for_uri(&self, uri: &Url) -> Option<String> {
        let doc_key = uri_to_key(uri);
        let workspace = self.workspace.read().await;
        let mut best: Option<(usize, String)> = None;
        for (key, node) in workspace.iter_recursively() {
            if doc_key.starts_with(&key)
                && (doc_key.len() == key.len() || doc_key.as_bytes().get(key.len()) == Some(&b'/'))
                && node.is_item()
            {
                let len = key.len();
                if best.as_ref().map(|(l, _)| *l < len).unwrap_or(true) {
                    best = Some((len, key.clone()));
                }
            }
        }
        best.map(|(_, k)| k)
    }

    /// 计算给定 URI 对应的 scene 键（相对于 scene/ 目录的路径，例如 `start.txt`）
    async fn find_scene_key_for_uri(&self, uri: &Url) -> Option<String> {
        // 优先使用文件系统路径进行匹配
        if let Ok(file_path) = uri.to_file_path()
            && let Some(project_key) = self.find_project_key_for_uri(uri).await
        {
            let scene_dir = std::path::PathBuf::from(&project_key).join("scene");
            if let Ok(rel) = file_path.strip_prefix(&scene_dir) {
                return Some(rel.to_string_lossy().replace('\\', "/"));
            }
        }

        // 回退到字符串前缀匹配
        if let Some(project_key) = self.find_project_key_for_uri(uri).await {
            let doc_key = uri_to_key(uri);
            let prefix = format!("{}/scene/", project_key);
            if doc_key.starts_with(&prefix) {
                return Some(doc_key[prefix.len()..].to_string());
            }
            let prefix2 = format!("{}/scene", project_key);
            if doc_key.starts_with(&prefix2) {
                return Some(doc_key[prefix2.len()..].trim_start_matches('/').to_string());
            }
        }

        None
    }
}

#[tower_lsp::async_trait]
impl LanguageServer for Backend {
    async fn initialize(&self, params: InitializeParams) -> Result<InitializeResult> {
        // 保存工作区文件夹以便启动时自动发现项目
        let mut wf = self.workspace_folders.write().await;
        *wf = params.workspace_folders.clone();

        Ok(InitializeResult {
            capabilities: ServerCapabilities {
                position_encoding: Some(PositionEncodingKind::UTF16), // 客户端不支持 UTF-8 :(
                text_document_sync: Some(TextDocumentSyncCapability::Options(
                    TextDocumentSyncOptions {
                        open_close: Some(true),
                        change: Some(TextDocumentSyncKind::FULL),
                        will_save: Some(true),
                        ..Default::default()
                    },
                )),
                completion_provider: Some(CompletionOptions {
                    trigger_characters: Some(vec![
                        ":".to_string(),
                        "-".to_string(),
                        "=".to_string(),
                        "/".to_string(),
                        "\\".to_string(),
                        "\"".to_string(),
                    ]),
                    completion_item: Some(CompletionOptionsCompletionItem {
                        label_details_support: Some(true),
                    }),
                    ..Default::default()
                }),
                document_formatting_provider: Some(OneOf::Left(true)),
                semantic_tokens_provider: Some(
                    SemanticTokensServerCapabilities::SemanticTokensRegistrationOptions(
                        SemanticTokensRegistrationOptions {
                            text_document_registration_options: TextDocumentRegistrationOptions {
                                document_selector: Some(vec![DocumentFilter {
                                    language: Some("webgal".to_string()),
                                    scheme: Some("file".to_string()),
                                    pattern: Some("**/scene/**/*.txt".to_string()),
                                }]),
                            },
                            semantic_tokens_options: SemanticTokensOptions {
                                work_done_progress_options: WorkDoneProgressOptions::default(),
                                legend: SemanticTokensLegend {
                                    token_types: supported_token_types().to_vec(),
                                    token_modifiers: vec![],
                                },
                                range: Some(false),
                                full: Some(SemanticTokensFullOptions::Bool(true)),
                            },
                            static_registration_options: StaticRegistrationOptions::default(),
                        },
                    ),
                ),
                workspace: Some(WorkspaceServerCapabilities {
                    workspace_folders: Some(WorkspaceFoldersServerCapabilities {
                        supported: Some(true),
                        change_notifications: Some(OneOf::Left(true)),
                    }),
                    file_operations: None,
                }),
                ..Default::default()
            },
            server_info: Some(ServerInfo {
                name: "webgal-ls".to_string(),
                version: None,
            }),
        })
    }

    async fn initialized(&self, _: InitializedParams) {
        let register_options = Registration {
            id: "watcher-scene-config".to_string(),
            method: "workspace/didChangeWatchedFiles".to_string(),
            register_options: Some(
                serde_json::to_value(DidChangeWatchedFilesRegistrationOptions {
                    watchers: vec![
                        FileSystemWatcher {
                            glob_pattern: GlobPattern::String("**/scene/**/*.txt".to_string()),
                            kind: Some(WatchKind::all()),
                        },
                        FileSystemWatcher {
                            glob_pattern: GlobPattern::String("**/config.txt".to_string()),
                            kind: Some(WatchKind::all()),
                        },
                    ],
                })
                .unwrap(),
            ),
        };
        let _ = self
            .client
            .register_capability(vec![register_options])
            .await;
        // 启动后自动发现工作区中的项目并预加载资源与场景
        self.discover_projects().await;
    }

    async fn shutdown(&self) -> Result<()> {
        Ok(())
    }

    async fn did_change_watched_files(&self, params: DidChangeWatchedFilesParams) {
        for event in params.changes {
            let uri = event.uri;
            if uri.path().ends_with("config.txt") {
                if event.typ == FileChangeType::CREATED {
                    let key = parent_key_from_uri(&uri);
                    let ctx = Context::new();
                    let arc = Arc::new(RwLock::new(ctx));
                    {
                        let mut workspace = self.workspace.write().await;
                        let _old = workspace.insert(&key, Node::Item(arc.clone()));
                    }
                    tracing::info!(%key, "Created project context for config");
                    // 扫描项目资源以填充刚创建的 Context
                    self.scan_project_resources(&key, &arc).await;
                } else if event.typ == FileChangeType::DELETED {
                    let key = parent_key_from_uri(&uri);
                    let mut workspace = self.workspace.write().await;
                    let removed = workspace.remove(&key);
                    tracing::info!(%key, removed = removed.is_some(), "Removed project context for config deletion");
                } else {
                    tracing::debug!(uri = %uri.as_str(), "config.txt changed (watcher)");
                }
            }
        }
    }

    async fn did_open(&self, params: DidOpenTextDocumentParams) {
        let uri = params.text_document.uri.clone();
        if uri.path().ends_with("config.txt") {
            let cfg = webgal_model::resource::Config::from_str(&params.text_document.text);
            let key = parent_key_from_uri(&uri);

            let ctx_arc = {
                let ws = self.workspace.read().await;
                ws.get(&key).and_then(|n| n.as_item()).cloned()
            };

            let ctx = if let Some(existing) = ctx_arc {
                existing
            } else {
                let ctx = Context::new();
                let arc = Arc::new(RwLock::new(ctx));
                {
                    let mut ws = self.workspace.write().await;
                    ws.insert(&key, Node::Item(arc.clone()));
                }
                arc
            };

            {
                let mut g = ctx.write().await;
                g.resource.config = cfg;
            }

            // 扫描项目资源与场景以预填充 Context
            tracing::debug!(%key, "Scanning resources and scenes for opened config");
            self.scan_project_resources(&key, &ctx).await;
            self.scan_all_scenes(&key, &ctx).await;
            self.publish_all_diagnostics(&ctx).await;
        } else {
            self.update(uri, params.text_document.text).await;
        }
    }

    async fn did_change(&self, params: DidChangeTextDocumentParams) {
        if let Some(change) = params.content_changes.into_iter().last() {
            let uri = params.text_document.uri.clone();
            if uri.path().ends_with("config.txt") {
                let cfg = webgal_model::resource::Config::from_str(&change.text);
                let key = parent_key_from_uri(&uri);

                if let Some(ctx_arc) = {
                    let ws = self.workspace.read().await;
                    ws.get(&key).and_then(|n| n.as_item()).cloned()
                } {
                    let mut g = ctx_arc.write().await;
                    g.resource.config = cfg;
                    // 更新后也重新扫描资源
                    drop(g);
                    tracing::debug!(%key, "Config changed: rescanning resources and scenes");
                    self.scan_project_resources(&key, &ctx_arc).await;
                    self.scan_all_scenes(&key, &ctx_arc).await;
                    self.publish_all_diagnostics(&ctx_arc).await;
                } else {
                    let mut ctx = Context::new();
                    ctx.resource.config = cfg;
                    let arc = Arc::new(RwLock::new(ctx));
                    {
                        let mut ws = self.workspace.write().await;
                        ws.insert(&key, Node::Item(arc.clone()));
                    }
                    // 新创建的 context 扫描资源与场景
                    tracing::debug!(%key, "New config created: scanning resources and scenes");
                    self.scan_project_resources(&key, &arc).await;
                    self.scan_all_scenes(&key, &arc).await;
                    self.publish_all_diagnostics(&arc).await;
                }
            } else {
                self.update(uri, change.text).await;
            }
        }
    }

    async fn semantic_tokens_full(
        &self,
        params: SemanticTokensParams,
    ) -> Result<Option<SemanticTokensResult>> {
        let uri = params.text_document.uri;
        if let Some(ctx_arc) = self.find_context_for_doc(&uri).await {
            if let Some(scene_key) = self.find_scene_key_for_uri(&uri).await {
                let ctx = ctx_arc.read().await;
                if let Some(scene) = ctx.resource.scene.get(&scene_key).and_then(Node::as_item) {
                    let tokens = highlight_scene(scene);
                    let tokens16 = semantic_tokens_utf8_to_utf16(scene, tokens);
                    return Ok(Some(SemanticTokensResult::Tokens(SemanticTokens {
                        result_id: None,
                        data: tokens16,
                    })));
                } else {
                    tracing::debug!(%scene_key, "scene not present in context, falling back to disk");
                }
            } else {
                tracing::debug!(%uri, "scene key not found for uri in context, falling back to disk");
            }
        } else {
            tracing::debug!(%uri, "no project context found, will try to load scene from disk");
        }

        tracing::error!("semantic tokens: no scene available for {}", uri);
        Err(Error::internal_error())
    }

    async fn formatting(&self, params: DocumentFormattingParams) -> Result<Option<Vec<TextEdit>>> {
        let uri = params.text_document.uri;
        let path = uri.path();
        if !path.contains("/scene/") || !path.ends_with(".txt") {
            return Ok(None);
        }

        let ctx_arc = match self.find_context_for_doc(&uri).await {
            Some(c) => c,
            None => return Ok(None),
        };

        let scene_key = match self.find_scene_key_for_uri(&uri).await {
            Some(k) => k,
            None => return Ok(None),
        };

        let ctx = ctx_arc.read().await;
        let scene = ctx
            .resource
            .scene
            .get(&scene_key)
            .and_then(Node::as_item)
            .ok_or_else(|| {
                tracing::error!(%scene_key, "formatting requested but scene not found");
                Error::internal_error()
            })?;

        let formatted = scene.to_string();
        let line_count = scene.sentences().len() as u32;
        let full_range = Range {
            start: Position::new(0, 0),
            end: Position::new(line_count, 0),
        };

        Ok(Some(vec![TextEdit {
            range: full_range,
            new_text: formatted,
        }]))
    }

    async fn completion(&self, params: CompletionParams) -> Result<Option<CompletionResponse>> {
        let tdpp = params.text_document_position.clone();
        let uri = tdpp.text_document.uri;
        let pos = tdpp.position;
        if !uri.path().contains("/scene/") {
            return Ok(None);
        }
        let ctx_arc = match self.find_context_for_doc(&uri).await {
            Some(c) => c,
            None => return Ok(None),
        };

        let scene_key = match self.find_scene_key_for_uri(&uri).await {
            Some(k) => k,
            None => return Ok(None),
        };

        let ctx = ctx_arc.read().await;
        let scene = match ctx.resource.scene.get(&scene_key).and_then(Node::as_item) {
            Some(s) => s,
            None => return Ok(None),
        };
        // 将客户端的 UTF-16 位置转换为服务器使用的 UTF-8 位置
        let utf8_pos = match position_utf16_to_utf8(scene, pos) {
            Some(p) => p,
            None => return Ok(None),
        };

        let mut items = complete_sentence(scene, utf8_pos, &ctx);
        // 将补全项中可能存在的 TextEdit.range 从 UTF-8 转回 UTF-16
        for item in &mut items {
            if let Some(te) = &mut item.text_edit
                && let CompletionTextEdit::Edit(edit) = te
                && let Some(r) = range_utf8_to_utf16(scene, edit.range)
            {
                edit.range = r;
            }
            if let Some(adds) = &mut item.additional_text_edits {
                for edit in adds.iter_mut() {
                    if let Some(r) = range_utf8_to_utf16(scene, edit.range) {
                        edit.range = r;
                    }
                }
            }
        }

        Ok(Some(CompletionResponse::Array(items)))
    }
}
